WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('min-stack','Data Structures','function','go','Min Stack','Design a data structure that supports push, pop, top, and retrieving the minimum element in O(1) time. Return an evaluation string: "push|pop|top|getMin" actions.','MinStack','[]interface{}',ARRAY['[]string']::text[],ARRAY['Maintain two stacks: one for values and one for current minimums.','On push: if value <= current min, push to minStack too.','On pop: if popped value equals minStack top, pop minStack too.'],2,110,ARRAY['stack','design','medium'],true,'MANUAL:min-stack',$$Implement a stack with O(1) minimum retrieval.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[["push","push","push","getMin","pop","top","getMin"]]'::jsonb,'[null,null,null,-2,null,0,-1]',false,1),('[["push","push","getMin","pop","getMin"]]'::jsonb,'[null,null,-1,null,0]',true,2)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('my-queue','Data Structures','function','go','Implement Queue using Stacks','Implement a FIFO queue using two stacks. Return evaluation results for a series of operations.','MyQueue','[]interface{}',ARRAY['[]string']::text[],ARRAY['Use two stacks: inStack for pushes, outStack for pops/peeks.','When outStack is empty, transfer all elements from inStack to outStack.','This gives amortised O(1) per operation.'],2,100,ARRAY['queue','stack','design','medium'],true,'MANUAL:my-queue',$$Implement a FIFO queue using two stacks.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[["push","push","peek","pop","empty"]]'::jsonb,'[null,null,1,1,false]',false,1),('[["push","pop","push","peek","pop","empty"]]'::jsonb,'[null,null,null,1,1,true]',true,2)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('circular-buffer','Data Structures','function','go','Circular Buffer','Implement a circular buffer with fixed capacity. Return result slice after a series of read/write operations.','CircularBuffer','[]interface{}',ARRAY['int','[]string']::text[],ARRAY['Use a slice of fixed size, head and tail pointers.','Write advances tail; read advances head (both modulo capacity).','Return the buffer contents in order (head to tail).'],2,90,ARRAY['buffer','design','medium'],true,'MANUAL:circular-buffer',$$Implement a circular buffer with fixed capacity.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[3,["write","write","write","read","write","read","read"]]'::jsonb,'[1,2,3,1,4,2,3]',false,1),('[2,["write","write","write","read","read"]]'::jsonb,'[1,2,null,1,2]',true,2)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

