WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('binary-search','Sorting & Searching','function','go','Binary Search','Given a sorted integer slice and a target value, return the index of target. If not found, return -1.','BinarySearch','int',ARRAY['[]int','int']::text[],ARRAY['Maintain left and right pointers.','Mid = left + (right-left)/2 to avoid overflow.','If nums[mid] < target, search right half; else search left half.'],1,50,ARRAY['searching','binary-search','basic'],true,'MANUAL:binary-search',$$Binary search a target in a sorted array.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[-1,0,3,5,9,12],9]'::jsonb,'4',false,1),('[[-1,0,3,5,9,12],2]'::jsonb,'-1',false,2),('[[1],1]'::jsonb,'0',false,3),('[[],5]'::jsonb,'-1',true,4)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('find-peak','Sorting & Searching','function','go','Find Peak Element','A peak element is strictly greater than its neighbours. Return the index of any peak element.','FindPeak','int',ARRAY['[]int']::text[],ARRAY['Use binary search: if mid > mid+1, peak in left half; else right half.','The array may have multiple peaks; return any one.','Edge case: single element is a peak (index 0).'],2,90,ARRAY['searching','binary-search','peak','medium'],true,'MANUAL:find-peak',$$Find any peak element in an array.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
