WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('find-kth-smallest','Sorting & Searching','function','go','Kth Smallest Element','Given an unsorted integer slice, return the kth smallest element (1-indexed). You may modify the input.','KthSmallest','int',ARRAY['[]int','int']::text[],ARRAY['Use quick select: partition like quicksort, then recurse on the relevant half.','If pivot index == k-1, return it.','Average O(n) time, worst-case O(n^2).'],3,130,ARRAY['searching','quickselect','divide-conquer','medium'],true,'MANUAL:find-kth-smallest',$$Find kth smallest element using quick select.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
INSERT INTO test_cases (problem_id,input,expected,is_hidden,ordinal) SELECT id,input,expected,is_hidden,ordinal FROM p,(VALUES ('[[3,2,1,5,6,4],2]'::jsonb,'2',false,1),('[[3,2,3,1,2,4,5,5,6],4]'::jsonb,'3',false,2),('[[1],1]'::jsonb,'1',true,3)) AS t(input,expected,is_hidden,ordinal) WHERE id IS NOT NULL;

WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('search-rotated','Sorting & Searching','function','go','Search in Rotated Sorted Array','A sorted array was rotated at an unknown pivot. Search for a target and return its index, or -1 if not found.','SearchRotated','int',ARRAY['[]int','int']::text[],ARRAY['Modified binary search: find which half is sorted.','If left half is sorted (nums[left] <= nums[mid]), check if target is in that range.','Otherwise check the right half.'],3,140,ARRAY['searching','binary-search','rotated','medium'],true,'MANUAL:search-rotated',$$Search in a rotated sorted array.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
