WITH p AS (INSERT INTO problems (slug,module,type,language,title,statement,func_name,return_type,param_types,hints,difficulty,xp_reward,tags,visible,source_hash,raw_readme) VALUES ('two-sum','Hash Maps & Sets','function','go','Two Sum','Given a slice of integers and a target integer, return the indices of the two numbers that add up to target. Exactly one solution exists.','TwoSum','[]int',ARRAY['[]int','int']::text[],ARRAY['Use a map[value]index to store seen elements.','For each element, check if target - element exists in the map.','If found, return [map[complement], currentIndex].'],1,50,ARRAY['hashmap','arrays','basic'],true,'MANUAL:two-sum',$$Find two numbers that sum to target.$$) ON CONFLICT (slug) DO NOTHING RETURNING id)
